import React, { useState } from 'react';
import { Form, Input, Button, Upload, message, Row, Col, Card } from 'antd';
import { UploadOutlined } from '@ant-design/icons';
import { uploadToCloudinary } from '../utils/cloudinary';

export default function AddUserForm({ onUserAdded }) {
  const [form] = Form.useForm();
  const [loading, setLoading] = useState(false);
  const [imageFile, setImageFile] = useState(null);
  const [fileList, setFileList] = useState([]);

  const handleImageChange = info => {
    setFileList(info.fileList);
    setImageFile(info.fileList[0]?.originFileObj || null);
  };

  const onFinish = async values => {
    setLoading(true);
    try {
      let profilePic = '';
      if (imageFile) {
        profilePic = await uploadToCloudinary(imageFile);
      }
      const res = await fetch('/api/users', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...values, profilePic }),
      });
      const data = await res.json();
      if (res.ok) {
        message.success('User added!');
        form.resetFields();
        setImageFile(null);
        setFileList([]);
        if (onUserAdded) onUserAdded(data.user);
      } else {
        message.error(data.message || 'Failed to add user');
      }
    } catch (err) {
      message.error('Failed to add user');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Card title="Add New User" style={{ marginBottom: 24 }}>
      <Form
        form={form}
        layout="vertical"
        onFinish={onFinish}
        autoComplete="off"
      >
        <Row gutter={16}>
          <Col xs={24} md={12}>
            <Form.Item label="Name" name="name" rules={[{ required: true, message: 'Please enter Name' }]}> <Input /> </Form.Item>
          </Col>
          <Col xs={24} md={12}>
            <Form.Item label="Email" name="email" rules={[{ required: true, type: 'email', message: 'Please enter Email' }]}> <Input /> </Form.Item>
          </Col>
          <Col xs={24} md={12}>
            <Form.Item label="Phone Number" name="phoneNumber" rules={[{ required: true, message: 'Please enter Phone Number' }]}> <Input /> </Form.Item>
          </Col>
          <Col xs={24} md={12}>
            <Form.Item label="NIC" name="nic" rules={[{ required: true, message: 'Please enter NIC' }]}> <Input /> </Form.Item>
          </Col>
          <Col xs={24} md={12}>
            <Form.Item label="Password" name="password" rules={[{ required: true, message: 'Please enter Password' }]}> <Input.Password /> </Form.Item>
          </Col>
          <Col xs={24} md={12}>
            <Form.Item label="Profile Photo">
              <Upload
                beforeUpload={() => false}
                onChange={handleImageChange}
                fileList={fileList}
                maxCount={1}
                accept="image/*"
                listType="picture"
              >
                <Button icon={<UploadOutlined />}>Select Image</Button>
              </Upload>
            </Form.Item>
          </Col>
        </Row>
        <Button type="primary" htmlType="submit" loading={loading}>
          Add User
        </Button>
      </Form>
    </Card>
  );
}
